async function processMessage(msg, channel) {
  let parsedMessage;

  try {
    parsedMessage = parseMessage(msg.content);
  } catch (err) {
    console.error(`Message parse/validation error: ${err.message}. Sending to dead letter queue.`);
    channel.nack(msg, false, false);
    return;
  }

  const { type, payload, correlationId } = parsedMessage;
  const handler = MESSAGE_HANDLERS[type];

  if (!handler) {
    console.error(`[${correlationId}] No handler for message type: ${type}. Dead-lettering.`);
    channel.nack(msg, false, false);
    return;
  }

  const retryCount = (msg.properties.headers && msg.properties.headers['x-retry-count']) || 0;

  try {
    console.log(`[${correlationId}] Processing message type: ${type}`);
    const result = await handler(payload, correlationId);
    console.log(`[${correlationId}] Successfully processed: ${type}`, result);
    channel.ack(msg);
  } catch (err) {
    console.error(`[${correlationId}] Error processing ${type}: ${err.message}`);

    if (retryCount < MAX_RETRIES) {
      console.log(`[${correlationId}] Retrying (${retryCount + 1}/${MAX_RETRIES})...`);
      channel.publish('', QUEUE_NAME, msg.content, {
        headers: { 'x-retry-count': retryCount + 1 },
        correlationId,
        persistent: true,
      });
      channel.ack(msg);
    } else {
      console.error(`[${correlationId}] Max retries exceeded. Dead-lettering.`);
      channel.nack(msg, false, false);
    }
  }
}

async function startConsumer() {
  let connection;
  let channel;

  try {
    connection = await amqplib.connect(RABBITMQ_URL);
    channel = await connection.createChannel();

    await channel.assertExchange('events_dlx', 'direct', { durable: true });
    await channel.assertQueue(DEAD_LETTER_QUEUE, { durable: true });
    await channel.bindQueue(DEAD_LETTER_QUEUE, 'events_dlx', QUEUE_NAME);

    await channel.assertQueue(QUEUE_NAME, {
      durable: true,
      arguments: {
        'x-dead-letter-exchange': 'events_dlx',
        'x-dead-letter-routing-key': QUEUE_NAME,
        'x-message-ttl': 86400000,
      },
    });

    const prefetchCount = parseInt(process.env.PREFETCH_COUNT, 10) || 10;
    await channel.prefetch(prefetchCount);

    console.log(`[*] Waiting for messages in ${QUEUE_NAME}. Prefetch: ${prefetchCount}`);

    channel.consume(QUEUE_NAME, (msg) => {
      if (msg !== null) {
        processMessage(msg, channel);
      }
    });

    connection.on('error', (err) => {
      console.error('RabbitMQ connection error:', err.message);
    });

    connection.on('close', () => {
      console.error('RabbitMQ connection closed. Reconnecting in 5s...');
      setTimeout(startConsumer, 5000);
    });
  } catch (err) {
    console.error('Failed to start consumer:', err.message);
    if (channel) {
      try { await channel.close(); } catch (_) {}
    }
    if (connection) {
      try { await connection.close(); } catch (_) {}
    }
    console.log('Retrying connection in 5s...');
    setTimeout(startConsumer, 5000);
  }
}

